/* --- ASTRAL GLASSMORPHISM --- */
* {
	border-color: rgba(100, 150, 255, 0.15) !important;
}

/* Ethereal Typography */
.prose h1, .prose h2, .prose h3, .prose h4 {
	color: #aaddff !important;
	text-shadow: 0 0 15px rgba(136, 187, 255, 0.2);
}
.prose code {
	color: #cdd3f5 !important;
	background-color: rgba(136, 187, 255, 0.1) !important;
	border: 1px solid rgba(136, 187, 255, 0.2);
	border-radius: 6px;
}

/* Frosted Glass Inputs */
input, textarea, .bg-gray-850 {
	background-color: rgba(10, 11, 20, 0.5) !important;
	backdrop-filter: blur(12px) !important;
	-webkit-backdrop-filter: blur(12px) !important;
	border: 1px solid rgba(136, 187, 255, 0.2) !important;
	border-radius: 12px !important;
	box-shadow: inset 0 0 10px rgba(0, 0, 0, 0.5);
	transition: all 0.3s ease;
}
input:focus, textarea:focus {
	border-color: #88bbff !important;
	background-color: rgba(16, 18, 35, 0.7) !important;
	box-shadow: 0 0 20px rgba(136, 187, 255, 0.2), inset 0 0 10px rgba(0, 0, 0, 0.5) !important;
}

/* Starship Buttons */
button.bg-blue-500, button.bg-blue-600, .bg-black {
	background: linear-gradient(135deg, #4488ff, #8855ff) !important;
	border: none !important;
	color: #ffffff !important;
	font-weight: 600 !important;
	border-radius: 20px !important;
	box-shadow: 0 4px 15px rgba(68, 136, 255, 0.3);
	transition: transform 0.2s cubic-bezier(0.4, 0, 0.2, 1), box-shadow 0.2s;
}
button.bg-blue-500:hover, button.bg-blue-600:hover, .bg-black:hover {
	transform: translateY(-3px) scale(1.02);
	box-shadow: 0 8px 25px rgba(136, 85, 255, 0.5) !important;
}

/* Liquid Scrollbar */
::-webkit-scrollbar-thumb {
	background: linear-gradient(to bottom, #4488ff, #8855ff) !important;
	border-radius: 10px;
}
::-webkit-scrollbar-track {
	background: rgba(5, 5, 10, 0.5) !important;
}
